        if isinstance(other, Field):
            return self.creation_counter < other.creation_counter
        return NotImplemented

    def __hash__(self):
        return hash(self.creation_counter)'''

new_eq = '''    def __eq__(self, other):
        # Needed for @total_ordering
        if isinstance(other, Field):
            return (
                self.creation_counter == other.creation_counter and
                (not hasattr(self, 'model') and not hasattr(other, 'model') or
                 getattr(self, 'model', None) == getattr(other, 'model', None))
            )
        return NotImplemented

    def __lt__(self, other):
        # This is needed because bisect does not take a comparison function.
        if isinstance(other, Field):
            if self.creation_counter != other.creation_counter:
                return self.creation_counter < other.creation_counter
            # If creation counters are equal, compare by model to ensure
            # consistent ordering for fields from different models.
            if hasattr(self, 'model') and hasattr(other, 'model'):
                return self.model.__module__ < other.model.__module__ or (
                    self.model.__module__ == other.model.__module__ and
                    self.model.__name__ < other.model.__name__
                )
            return False
        return NotImplemented

    def __hash__(self):
        if hasattr(self, 'model'):
            return hash((self.creation_counter, self.model))
        return hash(self.creation_counter)'''

assert old_eq in content, 'Could not find the old methods'
content = content.replace(old_eq, new_eq)

with open('django/db/models/fields/__init__.py', 'w') as f:
